sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onSubmit() {
	if (g_form.getActionName() == 'RunProcessTemplateModalUIAction') {

		// STRY0086102  - If the form is dirty, ask the user if they would like to save the record
		if((typeof spModal != 'undefined' && g_form.serialize(true).length>0)
		|| (typeof spModal == 'undefined' && g_form.modified)){
			if(confirm(getMessage('Tasker - Modal Save Changes Message'))){
				g_form.save();
			} else{
				return false;
			}
		}

		// STRY0075793 - implement in Native pages also
		if (typeof spModal != 'undefined' ) {
			spModal.open({
				title: 'Template Instance',
				backdrop:'static',
				widget: 'discovertasker-widget-modal-prompt',
				widgetInput: {process_template_sys_id: g_form.getUniqueValue()},
					buttons: [{label:'Close', cancel: true}]
					});
		// STRY0075793 - implement in Native pages also
		}else{
			// STRY0075793
			var modalForm = new GlideModalForm('Template Instance', 'x_153465_discovert_discover_routing_runtime');
			modalForm.addParm('sysparm_query','routing_template_ref='+g_form.getUniqueValue());
			modalForm.render();
			modalForm.setSysID(-1);
		}
		return false;
	}
}
